#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X, Y;
        scanf("%d %d", &X, &Y);
        int sum = X + Y;
        int win = 6 - sum;
        if (win < 0) win = 0;
        double prob = win / 6.0;
        printf("%.6f\n", prob);
    }
    return 0;
}

